from cryptography.fernet import Fernet

def encrypt_credit_card(credit_card_number):
    # Load encryption key from application config
    key = config['encryption_key']
    cipher_suite = Fernet(key.encode())

    # Encrypt credit card number
    encrypted_credit_card = cipher_suite.encrypt(credit_card_number.encode())

    # Return encrypted credit card number as string
    return encrypted_credit_card.decode()

def decrypt_credit_card(encrypted_credit_card):
    # Load encryption key from application config
    key = config['encryption_key']
    cipher_suite = Fernet(key.encode())

    # Decrypt credit card number
    decrypted_credit_card = cipher_suite.decrypt(encrypted_credit_card.encode()).decode()

    # Return decrypted credit card number as string
    return decrypted_credit_card